char* convertToTitle(int n) {
    char tmp[32]; int k = 0;
    while (n) {
        n--;
        tmp[k++] = 'A' + (n % 26);
        n /= 26;
    }
    char* res = malloc(k + 1);
    for (int i = 0; i < k; i++) res[i] = tmp[k - 1 - i];
    res[k] = 0; return res;
}
